/* ParcelServiceMapper.updMcpParcelServiceCodeInfo */
UPDATE  MCP_REQUEST_STATE@DL_MCP
   SET  TB_CD = #{tbCd, jdbcType=VARCHAR}
      , DLVRY_NO = REPLACE(#{dlvrNo, jdbcType=VARCHAR},'-','')
      , RVISN_ID = #{sessionUserId}
      , RVISN_DTTM = SYSDATE 
 WHERE  RES_NO = #{resNo, jdbcType=VARCHAR}


/* ParcelServiceMapper.updMspParcelServiceCodeInfo */
UPDATE  MSP_REQUEST_STATE
   SET  TB_CD = #{tbCd, jdbcType=VARCHAR}
      , DLVRY_NO = REPLACE(#{dlvrNo, jdbcType=VARCHAR},'-','')
 WHERE  RES_NO = #{resNo, jdbcType=VARCHAR}


/* ParcelServiceMapper.updMspRequest */
UPDATE  MCP_REQUEST@DL_MCP
   SET RVISN_ID = #{sessionUserId}
      , RVISN_DTTM = SYSDATE 
 WHERE  RES_NO = #{resNo, jdbcType=VARCHAR}

/* ParcelServiceMapper.updMspRequestByParcelInfo */
UPDATE MSP_REQUEST
SET REQUEST_STATE_CODE = #{requestStateCode, jdbcType=VARCHAR}
WHERE  RES_NO = #{resNo, jdbcType=VARCHAR}
AND    REQUEST_STATE_CODE = '10'

/* ParcelServiceMapper.updMcpRequestByParcelInfo */
UPDATE MCP_REQUEST@DL_MCP
SET RVISN_ID = #{sessionUserId}
	, RVISN_DTTM = SYSDATE
	, REQUEST_STATE_CODE = #{requestStateCode, jdbcType=VARCHAR}
WHERE  RES_NO = #{resNo, jdbcType=VARCHAR}
AND    REQUEST_STATE_CODE = '10'

/* ParcelServiceMapper.updMspRequestStateByParcelInfo */
UPDATE MSP_REQUEST_STATE
SET  REQUEST_STATE_CODE = #{requestStateCode, jdbcType=VARCHAR}
WHERE  RES_NO = #{resNo, jdbcType=VARCHAR}
AND    REQUEST_STATE_CODE = '10'

/* ParcelServiceMapper.updMcpRequestStateByParcelInfo */
UPDATE MCP_REQUEST_STATE@DL_MCP
SET RVISN_ID = #{sessionUserId}
	, RVISN_DTTM = SYSDATE
	, REQUEST_STATE_CODE = #{requestStateCode, jdbcType=VARCHAR}
WHERE  RES_NO = #{resNo, jdbcType=VARCHAR}
AND    REQUEST_STATE_CODE = '10'

